test('fetch roundtrip — quotes endpoint (median of 3)', async ({ page, baseURL }) => {
  await page.goto('/report/');
  await waitForPageReady(page);

  // Warm-up run — first call pays SQLAlchemy compile + JIT warmup costs.
  await page.evaluate(async (url: string) => {
    const token = (window as unknown as { __BRISTLENOSE_AUTH_TOKEN__?: string })
      .__BRISTLENOSE_AUTH_TOKEN__;
    await fetch(`${url}/api/projects/1/quotes`, {
      headers: token ? { Authorization: `Bearer ${token}` } : {},
    });
  }, baseURL!);

  const samples: number[] = [];
  for (let i = 0; i < 3; i++) {
    const { ms, ok, status } = await page.evaluate(async (url: string) => {
      const token = (window as unknown as { __BRISTLENOSE_AUTH_TOKEN__?: string })
        .__BRISTLENOSE_AUTH_TOKEN__;
      const start = performance.now();
      const res = await fetch(`${url}/api/projects/1/quotes`, {
        headers: token ? { Authorization: `Bearer ${token}` } : {},
      });
      return { ms: performance.now() - start, ok: res.ok, status: res.status };
    }, baseURL!);
    expect(ok, `quotes API returned ${status}`).toBe(true);
    samples.push(ms);
  }

  const med = median(samples);
  results.fetch_roundtrip_ms.quotes = Math.round(med * 10) / 10;
  console.log(`  /api/projects/1/quotes: ${med.toFixed(1)}ms median`);
});

