test('Interaction — search DOM delta', async ({ page }) => {
  await page.goto('/report/quotes/');
  await waitForPageReady(page);

  const before = await page.evaluate(
    () => document.querySelectorAll('*').length,
  );

  // The toolbar hides its search behind a toggle; we only measure when
  // the input is actually visible.  This is a soft metric — skipping it
  // is fine, the scale signal comes from DOM counts.
  const searchBox = page.locator(
    '[data-testid="bn-toolbar-search-input"], [data-testid="search-input"], input.search-input',
  ).first();

  if ((await searchBox.count()) === 0 || !(await searchBox.isVisible().catch(() => false))) {
    results.interaction_deltas.search_delta = -1;
    console.log('  search input not visible — skipping search delta');
    return;
  }

  await searchBox.fill('dashboard');
  await page.waitForTimeout(500); // debounce

  const after = await page.evaluate(
    () => document.querySelectorAll('*').length,
  );
  results.interaction_deltas.search_delta = after - before;
  results.interaction_deltas.search_after = after;
  console.log(`  search delta: ${after - before} (${before} → ${after})`);
});

// ── Write results ──────────────────────────────────────────────────────

test.afterAll(() => {
  const outPath =
    process.env.STRESS_RESULTS_PATH ??
    resolve(__dirname, '..', 'stress-results.json');

  const record = {
    timestamp: new Date().toISOString(),
    ...results,
  };
  writeFileSync(outPath, JSON.stringify(record, null, 2) + '\n');

  const lines = [
    '',
    '┌── Stress measurements ───────────────────────────────────┐',
    `│  Project: ${(results.project_name ?? '?').padEnd(46)}│`,
    '├──────────────────────────────────────────────────────────┤',
    ...Object.entries(results.dom).map(
      ([k, v]) => `│  dom.${k.padEnd(24)} ${String(v).padStart(8)} nodes      │`,
    ),
    ...Object.entries(results.fetch_roundtrip_ms).map(
      ([k, v]) => `│  fetch.${k.padEnd(22)} ${String(v).padStart(8)} ms         │`,
    ),
    ...Object.entries(results.paint_ms).map(
      ([k, v]) => `│  paint.${k.padEnd(22)} ${String(v).padStart(8)} ms         │`,
    ),
    ...Object.entries(results.interaction_deltas).map(
      ([k, v]) => `│  ui.${k.padEnd(25)} ${String(v).padStart(8)}            │`,
    ),
    ...Object.entries(results.heap_mb).map(
      ([k, v]) => `│  heap.${k.padEnd(23)} ${String(v).padStart(8)} MB         │`,
    ),
    '└──────────────────────────────────────────────────────────┘',
    `  Saved: ${outPath}`,
    '',
  ];
  console.log(lines.join('\n'));
});
